import 'package:flutter/foundation.dart';import 'package:sqlite3/wasm.dart';import 'package:sqlite3_simple/web.dart';import '../../db_manager.dart';import '../../impl/sqlite3/sqlite3_dao.dart';class Sqlite3WasmDbManager extends DbManager<Sqlite3Dao> {  @override  late final Sqlite3Dao dao;  late WasmSqlite3 wasmSqlite3;  final inMemoryFileSystem = InMemoryFileSystem();  @override  Future<void> init() async {    wasmSqlite3 = await WasmSqlite3.loadFromUrl(      Uri.parse('sqlite3.debug.wasm'),      loader: await DefaultSimpleWasmModuleLoader.create(jiebaDictBundle: const JiebaDictBundle()),    );    wasmSqlite3.registerVirtualFileSystem(      inMemoryFileSystem,      makeDefault: true,    );    final db = wasmSqlite3.open('/database');    dao = Sqlite3Dao(db);    final init = db.select("SELECT jieba_query('Jieba分词初始化（提前加载避免后续等待）')");    if (kDebugMode) print(init);    await dao.initFts5();  }  @override  Future<void> close() async {    wasmSqlite3.unregisterVirtualFileSystem(inMemoryFileSystem);  }}